import{_ as l,c as i,o as t,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const g=JSON.parse('{"title":"v1.1.54：Skill URL 发现、ACP 写文件更稳、模型报错更清晰","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.54.md","filePath":"changelog/v1.1.54.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.54.md"};function n(s,e,d,h,c,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-54-skill-url-发现、acp-写文件更稳、模型报错更清晰" tabindex="-1">v1.1.54：Skill URL 发现、ACP 写文件更稳、模型报错更清晰 <a class="header-anchor" href="#v1-1-54-skill-url-发现、acp-写文件更稳、模型报错更清晰" aria-label="Permalink to “v1.1.54：Skill URL 发现、ACP 写文件更稳、模型报错更清晰”">​</a></h1><p><strong>发布日期</strong>：2026年02月11日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新把「大版本里最容易踩坑的地方」补齐了：Skill 能通过 URL 自动发现、ACP 写文件会自动创建新文件、模型选择错误会给明确事件和错误类型，桌面端与 TUI 也修掉了一批高频问题。</p><hr><h2 id="新功能-skill-支持通过-url-自动发现" tabindex="-1">新功能：Skill 支持通过 URL 自动发现 <a class="header-anchor" href="#新功能-skill-支持通过-url-自动发现" aria-label="Permalink to “新功能：Skill 支持通过 URL 自动发现”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>OpenCode 新增了基于 well-known RFC 的 Skill URL 发现能力，后续通过 URL 接入 Skill 更顺滑。</p><h3 id="这对你有什么用" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>以前你需要手动找 Skill 入口；现在可以直接从标准 URL 走发现流程，尤其适合团队统一分发 Skill。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/03b-skills-advanced.html">Skill 进阶</a></p><p>👉 <strong>官方文档</strong>：<a href="https://opencode.ai/docs/agents" target="_blank" rel="noreferrer">Agents</a></p><p><strong>快速体验</strong>：</p><ol><li>先确认你的 Skill 来源地址可公开访问。</li><li>在项目里按已有 Skill 流程配置并触发加载。</li><li>观察是否按 URL 自动发现并加载对应 Skill。</li></ol><hr><h2 id="新功能-acp-写文件时自动创建不存在的文件" tabindex="-1">新功能：ACP 写文件时自动创建不存在的文件 <a class="header-anchor" href="#新功能-acp-写文件时自动创建不存在的文件" aria-label="Permalink to “新功能：ACP 写文件时自动创建不存在的文件”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>通过 ACP 通道写文件时，如果目标文件不存在，OpenCode 现在会自动创建文件再写入。</p><h3 id="这对你有什么用-1" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用-1" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>你在 IDE + ACP 场景下执行写入操作，不再因为「文件还没建」直接失败，自动化脚本更稳定。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/08b-acp.html">ACP 协议</a></p><p>👉 <strong>官方文档</strong>：<a href="https://opencode.ai/docs/acp" target="_blank" rel="noreferrer">ACP Support</a></p><p><strong>快速体验</strong>：</p><ol><li>按教程启动 ACP（<code>opencode acp</code>）。</li><li>让 Agent 向一个不存在的路径写入文件。</li><li>确认文件被创建并写入成功。</li></ol><hr><h2 id="新功能-模型选择错误事件与报错类型增强" tabindex="-1">新功能：模型选择错误事件与报错类型增强 <a class="header-anchor" href="#新功能-模型选择错误事件与报错类型增强" aria-label="Permalink to “新功能：模型选择错误事件与报错类型增强”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增 <code>session.error</code> 事件用于无效模型选择；同时新增 <code>ContextOverflowError</code>，并改进模型变体可用性检查逻辑。</p><h3 id="这对你有什么用-2" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用-2" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>排查模型问题时不再是「静默失败」或模糊报错，日志和事件会更快告诉你哪里错了。</p><h3 id="如何使用-2" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-2" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/01a-config-basics.html">配置基础</a></p><p>👉 <strong>延伸教程</strong>：<a href="/5-advanced/21-thinking-depth.html">思考深度配置</a></p><p>👉 <strong>官方文档</strong>：<a href="https://opencode.ai/docs/models" target="_blank" rel="noreferrer">Models</a></p><p><strong>快速体验</strong>：</p><ol><li>在配置里故意填一个不存在的模型 ID。</li><li>启动会话并观察事件或日志输出。</li><li>改回可用模型，验证会话恢复正常。</li></ol><hr><h2 id="问题修复-桌面端-tui-core-多项稳定性修复" tabindex="-1">问题修复：桌面端 / TUI / Core 多项稳定性修复 <a class="header-anchor" href="#问题修复-桌面端-tui-core-多项稳定性修复" aria-label="Permalink to “问题修复：桌面端 / TUI / Core 多项稳定性修复”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>包括 Homebrew 升级偶发需要多次运行、应用内终端回放异常、工作区重置后行为不稳定等。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>这些问题在 v1.1.54 中集中修复，桌面端、TUI 和核心流程稳定性明显提升。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>你在用 ACP 或 IDE 集成</td><td>✅ 建议立即升级</td></tr><tr><td>你经常切换模型/变体</td><td>✅ 建议立即升级</td></tr><tr><td>你主要用桌面端</td><td>✅ 建议升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',49),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-节选" tabindex="-1">Core（节选） <a class="header-anchor" href="#core-节选" aria-label="Permalink to “Core（节选）”">​</a></h3><ul><li>Publish session.error event for invalid model selection</li><li>Create file if it doesn&#39;t exist when writing via ACP</li><li>Add new ContextOverflowError type</li><li>Add skill discovery from URLs via well-known RFC</li><li>Parse mid-stream OpenAI response errors to prevent infinite retries</li><li>Resolve Homebrew upgrade requiring multiple runs</li></ul><h3 id="tui-节选" tabindex="-1">TUI（节选） <a class="header-anchor" href="#tui-节选" aria-label="Permalink to “TUI（节选）”">​</a></h3><ul><li>Use sender color for queued messages in TUI</li><li>Add --fork flag to duplicate sessions before continuing</li><li>Improve skills dialog readability</li></ul><h3 id="desktop-节选" tabindex="-1">Desktop（节选） <a class="header-anchor" href="#desktop-节选" aria-label="Permalink to “Desktop（节选）”">​</a></h3><ul><li>Fix terminal replay issues in app</li><li>Fix workspace reset and session navigation issues</li><li>Improve prompt input, sidebar, and file tree interactions</li><li>Add native Wayland toggle and more menu bar capabilities</li></ul><p>官方 Release Notes：</p><ul><li><a href="https://github.com/anomalyco/opencode/releases/tag/v1.1.54" target="_blank" rel="noreferrer">https://github.com/anomalyco/opencode/releases/tag/v1.1.54</a></li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const k=l(o,[["render",n]]);export{g as __pageData,k as default};
